import{_ as n,o as s,c as t,a3 as e}from"./chunks/framework.BTFg6ESq.js";const c=JSON.parse('{"title":"LLM AI 服务配置","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/llm-service.md","filePath":"user-guide/settings/llm-service.md","lastUpdated":1778241999000}'),l={name:"user-guide/settings/llm-service.md"};function i(r,a,o,p,h,d){return s(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="llm-ai-服务配置" tabindex="-1">LLM AI 服务配置 <a class="header-anchor" href="#llm-ai-服务配置" aria-label="Permalink to &quot;LLM AI 服务配置&quot;">​</a></h1><blockquote><p>这是使用 AIO Hub LLM 对话功能前的<strong>核心前提配置</strong>。管理 LLM API 提供商渠道，支持多渠道管理、多密钥负载均衡及深度模型配置。</p></blockquote><hr><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在左侧导航栏中选择 <strong>LLM AI 服务配置</strong>。</li></ol><hr><h2 id="界面布局" tabindex="-1">界面布局 <a class="header-anchor" href="#界面布局" aria-label="Permalink to &quot;界面布局&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────┬──────────────────────────────────────────┐</span></span>
<span class="line"><span>│   渠道列表（侧栏） │    渠道编辑区（右侧主面板）              │</span></span>
<span class="line"><span>│                    │                                          │</span></span>
<span class="line"><span>│  ┌──────────────┐  │  ┌────────────────────────────────────┐  │</span></span>
<span class="line"><span>│  │ OpenAI       │  │  │  # 基本信息                        │  │</span></span>
<span class="line"><span>│  │ DeepSeek     │  │  │  · 渠道名称、API 类型、图标        │  │</span></span>
<span class="line"><span>│  │ Claude       │  │  │  · API 地址                        │  │</span></span>
<span class="line"><span>│  │ + 新建渠道   │  │  ├────────────────────────────────────┤  │</span></span>
<span class="line"><span>│  └──────────────┘  │  │  # 网络设置（折叠）                │  │</span></span>
<span class="line"><span>│                    │  │  · 代理方案、证书校验、请求头      │  │</span></span>
<span class="line"><span>│                    │  ├────────────────────────────────────┤  │</span></span>
<span class="line"><span>│                    │  │  # 多密钥管理                      │  │</span></span>
<span class="line"><span>│                    │  │  · 逗号分隔/弹窗管理               │  │</span></span>
<span class="line"><span>│                    │  ├────────────────────────────────────┤  │</span></span>
<span class="line"><span>│                    │  │  # 模型管理                        │  │</span></span>
<span class="line"><span>│                    │  │  · 模型列表（分组/展开）           │  │</span></span>
<span class="line"><span>│                    │  │  · 新增/编辑/删除/获取             │  │</span></span>
<span class="line"><span>│                    │  │  · 连接测试                        │  │</span></span>
<span class="line"><span>│                    |  └────────────────────────────────────┘  │</span></span>
<span class="line"><span>└────────────────────┴──────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="步骤一-创建渠道" tabindex="-1">步骤一：创建渠道 <a class="header-anchor" href="#步骤一-创建渠道" aria-label="Permalink to &quot;步骤一：创建渠道&quot;">​</a></h2><p>点击渠道列表顶部的「新建渠道」按钮，选择创建方式：</p><ul><li><strong>预设模板</strong>：从常用服务商（如 OpenAI、DeepSeek、Claude 等）的预设模板中选择，API 地址、快捷链接等配置将自动填充。</li><li><strong>空白</strong>：从零开始手动配置。</li></ul><hr><h2 id="步骤二-配置基本信息与网络" tabindex="-1">步骤二：配置基本信息与网络 <a class="header-anchor" href="#步骤二-配置基本信息与网络" aria-label="Permalink to &quot;步骤二：配置基本信息与网络&quot;">​</a></h2><h3 id="_1-核心字段" tabindex="-1">1. 核心字段 <a class="header-anchor" href="#_1-核心字段" aria-label="Permalink to &quot;1. 核心字段&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">字段</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>渠道名称</strong></td><td style="text-align:left;">自定义名称，方便在对话工具中识别。</td></tr><tr><td style="text-align:left;"><strong>API 格式类型</strong></td><td style="text-align:left;">选择兼容的格式（如 OpenAI-style, Google Gemini, Anthropic 等）。</td></tr><tr><td style="text-align:left;"><strong>供应商图标</strong></td><td style="text-align:left;">自定义图标路径或从预设图标库中选取。</td></tr><tr><td style="text-align:left;"><strong>API 地址</strong></td><td style="text-align:left;">服务的 API 端点。点击「重置」可恢复该类型的默认地址。下方会实时显示端点预览。</td></tr></tbody></table><h3 id="_2-网络设置-折叠面板" tabindex="-1">2. 网络设置（折叠面板） <a class="header-anchor" href="#_2-网络设置-折叠面板" aria-label="Permalink to &quot;2. 网络设置（折叠面板）&quot;">​</a></h3><p>针对复杂的网络环境，AIO Hub 提供了深度微调选项：</p><ul><li><strong>网络方案</strong>： <ul><li><strong>自动选择/后端代理</strong>：默认推荐。使用 Rust 后端代理请求，可绕过浏览器 CORS 限制，支持底层网络微调。</li><li><strong>原生请求</strong>：直接由浏览器前端发起请求，受安全策略限制较多。</li></ul></li><li><strong>代理行为</strong>：支持「放宽证书校验」（用于自签名证书）和「强制 HTTP/1.1」（提高与旧版 API 或某些代理的兼容性）。</li><li><strong>自定义请求头</strong>：可为该渠道所有请求附加特定的 HTTP Header。</li><li><strong>高级端点</strong>：允许覆盖特定操作（如 <code>chat/completions</code> 或 <code>embeddings</code>）的具体路径。</li></ul><hr><h2 id="步骤三-管理-api-key-与负载均衡" tabindex="-1">步骤三：管理 API Key 与负载均衡 <a class="header-anchor" href="#步骤三-管理-api-key-与负载均衡" aria-label="Permalink to &quot;步骤三：管理 API Key 与负载均衡&quot;">​</a></h2><p>AIO Hub 支持<strong>多密钥管理</strong>，能够有效应对速率限制（Rate Limit）。</p><ol><li><strong>快速输入</strong>：在密钥框中输入，多个 Key 请使用英文逗号分隔。</li><li><strong>状态管理弹窗</strong>：点击「管理密钥状态」进入高级管理界面： <ul><li><strong>健康度监控</strong>：实时查看每个 Key 的错误计数和最后报错信息。</li><li><strong>自动熔断</strong>：开启后，若某个 Key 报错（如 429），系统将自动暂时禁用。</li><li><strong>自动恢复</strong>：可设置在指定分钟后自动尝试重新启用已熔断的 Key。</li><li><strong>批量操作</strong>：支持批量导入、导出、测试连通性以及一键清理失效密钥。</li></ul></li></ol><hr><h2 id="步骤四-深度模型配置" tabindex="-1">步骤四：深度模型配置 <a class="header-anchor" href="#步骤四-深度模型配置" aria-label="Permalink to &quot;步骤四：深度模型配置&quot;">​</a></h2><p>模型管理是渠道配置的核心。点击「添加模型」或「编辑」图标进入详细配置：</p><h3 id="_1-基本信息与预设" tabindex="-1">1. 基本信息与预设 <a class="header-anchor" href="#_1-基本信息与预设" aria-label="Permalink to &quot;1. 基本信息与预设&quot;">​</a></h3><ul><li><strong>模型 ID</strong>：API 调用时的真实 ID。</li><li><strong>应用预设</strong>：输入 ID 后点击「应用预设」，系统将自动匹配并填充名称、分组、图标和模型能力。</li></ul><h3 id="_2-模型能力开关" tabindex="-1">2. 模型能力开关 <a class="header-anchor" href="#_2-模型能力开关" aria-label="Permalink to &quot;2. 模型能力开关&quot;">​</a></h3><p>通过开关精确控制该模型在 UI 中展现的功能：</p><ul><li><strong>文本生成 / 流式输出</strong>：基础对话能力。</li><li><strong>图片输入 (Vision)</strong>：是否支持视觉分析。</li><li><strong>工具调用 (Function Calling)</strong>：是否支持调用外部插件。</li><li><strong>思考能力 (Reasoning)</strong>：针对深度思考模型（如 o1, r1），可配置配置模式（开关、预算或等级模式）。</li></ul><h3 id="_3-token-限制与价格" tabindex="-1">3. Token 限制与价格 <a class="header-anchor" href="#_3-token-限制与价格" aria-label="Permalink to &quot;3. Token 限制与价格&quot;">​</a></h3><ul><li><strong>上下文窗口</strong>：配置模型支持的最大 Token 总数。</li><li><strong>输出限制</strong>：限制单次响应的最大生成长度。</li><li><strong>价格配置</strong>：设置输入、输出、请求及图像的单价，用于对话时的成本预估。</li></ul><h3 id="_4-高级配置" tabindex="-1">4. 高级配置 <a class="header-anchor" href="#_4-高级配置" aria-label="Permalink to &quot;4. 高级配置&quot;">​</a></h3><ul><li><strong>自定义参数</strong>：使用 JSON 格式为该模型指定非标准的专属 API 参数（如特定的 <code>top_p</code> 或供应商专属字段）。</li><li><strong>后处理规则</strong>：配置该模型默认开启的后处理逻辑（如自动提取代码块、思维链过滤等）。</li></ul><hr><h2 id="连接测试" tabindex="-1">连接测试 <a class="header-anchor" href="#连接测试" aria-label="Permalink to &quot;连接测试&quot;">​</a></h2><ul><li><strong>一键测试</strong>：点击 API Key 旁的「测试连接」，系统将使用配置的第一个模型进行快速握手。</li><li><strong>单模型测试</strong>：在模型列表中点击测试图标，验证特定模型的可用性。</li><li><strong>单密钥测试</strong>：在多密钥管理弹窗中，针对特定 Key 进行连通性验证。</li></ul><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-配置完成后在哪里使用-ai-功能" tabindex="-1">Q：配置完成后在哪里使用 AI 功能？ <a class="header-anchor" href="#q-配置完成后在哪里使用-ai-功能" aria-label="Permalink to &quot;Q：配置完成后在哪里使用 AI 功能？&quot;">​</a></h3><p>在 <strong>LLM 智能对话</strong> 工具中，选择你配置好的渠道和模型即可开始对话。</p><h3 id="q-多-api-key-的负载均衡策略是什么" tabindex="-1">Q：多 API Key 的负载均衡策略是什么？ <a class="header-anchor" href="#q-多-api-key-的负载均衡策略是什么" aria-label="Permalink to &quot;Q：多 API Key 的负载均衡策略是什么？&quot;">​</a></h3><p>系统采用<strong>轮询策略</strong>。如果当前使用的 Key 请求失败且触发了熔断，系统会自动切换到下一个健康密钥重试。</p><h3 id="q-为什么我的模型无法上传图片" tabindex="-1">Q：为什么我的模型无法上传图片？ <a class="header-anchor" href="#q-为什么我的模型无法上传图片" aria-label="Permalink to &quot;Q：为什么我的模型无法上传图片？&quot;">​</a></h3><p>请检查该模型的「模型能力」配置中是否开启了「图片输入」开关。</p>`,46)])])}const u=n(l,[["render",i]]);export{c as __pageData,u as default};
